1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE = 25;
3	const BLOCK_OF_THREE_BASE = 60;
4	
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	const INSURANCE_VALUES: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	type Item = {
37	  type: string;
38	  material?: string;
39	  enchantment?: number;
40	  cursed?: boolean;
41	};
42	type QuoteStep = { op: "quote"; items: Item[] };
43	type Damage = { itemType: string; amount: number };
44	type Incident = { cause: string; damages: Damage[] };
45	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
46	type Step = QuoteStep | ClaimStep;
47	type Customer = { yearsWithMHPCO: number };
48	type Scenario = { customer: Customer; steps: Step[] };
49	type QuoteResult = { premium: number };
50	type ClaimResult = { payout: number; remainingCap: number };
51	type StepResult = QuoteResult | ClaimResult;
52	type ScenarioResult = { results: StepResult[] };
53	
54	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
55	
56	const isKnownType = (item: Item): boolean =>
57	  item.type in BASE_PREMIUMS || COMPONENT_TYPES.has(item.type);
58	
59	const validateItems = (items: Item[]): void => {
60	  for (const item of items) {
61	    if (!isKnownType(item)) {
62	      throw new Error(`Unknown item type: ${item.type}`);
63	    }
64	  }
65	};
66	
67	const countBy = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
68	  const counts = new Map<string, number>();
69	  for (const value of values) {
70	    const key = keyOf(value);
71	    counts.set(key, (counts.get(key) ?? 0) + 1);
72	  }
73	  return counts;
74	};
75	
76	const countByType = (items: Item[]): Map<string, number> =>
77	  countBy(items, (item) => item.type);
78	
79	const componentTypeBase = (count: number): number =>
80	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
81	
82	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
83	
84	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
85	
86	const mainItemSurcharge = (item: Item): number => {
87	  const base = mainItemBase(item);
88	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
89	  const highEnch =
90	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
91	  return cursed + highEnch;
92	};
93	
94	const mainItemsBase = (mainItems: Item[]): number => sum(mainItems.map(mainItemBase));
95	
96	const componentsBase = (components: Item[]): number => {
97	  const counts = countByType(components);
98	  return sum([...counts.values()].map(componentTypeBase));
99	};
100	
101	const itemSurcharges = (mainItems: Item[]): number => sum(mainItems.map(mainItemSurcharge));
102	
103	const policyBase = (mainItems: Item[], components: Item[]): number =>
104	  mainItemsBase(mainItems) + componentsBase(components);
105	
106	const loyaltyDiscount = (base: number, customer: Customer): number =>
107	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
108	
109	const insuranceSum = (items: Item[]): number =>
110	  sum(items.map((item) => INSURANCE_VALUES[item.type] ?? 0));
111	
112	type Policy = { items: Item[]; cap: number; remainingCap: number };
113	
114	const quote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { result: QuoteResult; policy: Policy } => {
115	  validateItems(step.items);
116	  const mainItems = step.items.filter((item) => !isComponent(item));
117	  const components = step.items.filter(isComponent);
118	  const base = policyBase(mainItems, components);
119	  const surcharges = itemSurcharges(mainItems);
120	  const firstInsurance = base * FIRST_INSURANCE_RATE;
121	  const loyalty = loyaltyDiscount(base, customer);
122	  const followUp = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
123	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
124	  const cap = insuranceSum(step.items) * CAP_MULTIPLIER;
125	  return { result: { premium }, policy: { items: step.items, cap, remainingCap: cap } };
126	};
127	
128	const reimbursementRate = (item: Item | undefined): number =>
129	  item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
130	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
131	    : 1;
132	
133	const damagePayout = (damage: Damage, policy: Policy): number => {
134	  const item = policy.items.find((i) => i.type === damage.itemType);
135	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
136	};
137	
138	const totalDamagePayout = (damages: Damage[], policy: Policy): number =>
139	  sum(damages.map((d) => damagePayout(d, policy)));
140	
141	const validateDamages = (damages: Damage[], policy: Policy): void => {
142	  for (const d of damages) {
143	    if (d.amount < 0) {
144	      throw new Error(`Negative damage amount: ${d.amount}`);
145	    }
146	  }
147	  const insuredCounts = countByType(policy.items);
148	  const damagedCounts = countBy(damages, (d) => d.itemType);
149	  for (const [type, count] of damagedCounts) {
150	    if (count > (insuredCounts.get(type) ?? 0)) {
151	      throw new Error(`Damage entries exceed insured count for type: ${type}`);
152	    }
153	  }
154	};
155	
156	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
157	  validateDamages(step.incident.damages, policy);
158	  const rawPayout = totalDamagePayout(step.incident.damages, policy);
159	  const payout = Math.min(rawPayout, policy.remainingCap);
160	  policy.remainingCap -= payout;
161	  return { payout, remainingCap: policy.remainingCap };
162	};
163	
164	export const runScenario = (scenario: Scenario): ScenarioResult => {
165	  const policies: Policy[] = [];
166	  const results: StepResult[] = [];
167	  for (const step of scenario.steps) {
168	    if (step.op === "quote") {
169	      const isFollowUp = policies.length > 0;
170	      const { result, policy } = quote(step, scenario.customer, isFollowUp);
171	      policies.push(policy);
172	      results.push(result);
173	    } else {
174	      results.push(claim(step, policies[step.policy]));
175	    }
176	  }
177	  return { results };
178	};
